## 3.1 LAB TASK 1 — SQLite: Student Record Manager

### Step 1: Add the `DBHelper` Class

```java
// DBHelper.java
// WHY: To manage database creation, versioning, and provide CRUD methods.
package com.example.ktusqlite;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

public class DBHelper extends SQLiteOpenHelper {

    // --- DATABASE METADATA (Standard constants) ---
    private static final String DB_NAME   = "studentDB";       // logical DB name
    private static final int    DB_VERSION = 1;                // increment to trigger onUpgrade

    // --- TABLE METADATA ---
    private static final String TABLE_NAME = "student";
    private static final String COL_ID     = "id";
    private static final String COL_NAME   = "name";
    private static final String COL_COURSE = "course";

    // Constructor: passes context and metadata to the parent SQLiteOpenHelper.
    public DBHelper(Context context) {
        super(context, DB_NAME, null, DB_VERSION);
    }

    // onCreate() is called ONLY the first time the database is created.
    @Override
    public void onCreate(SQLiteDatabase db) {
        // HOW: Execute raw SQL to create the table.
        String createQuery =
            "CREATE TABLE " + TABLE_NAME + " (" +
                COL_ID     + " INTEGER PRIMARY KEY AUTOINCREMENT, " +
                COL_NAME   + " TEXT, " +
                COL_COURSE + " TEXT)";
        db.execSQL(createQuery);
    }

    // onUpgrade() is called when DB_VERSION is incremented.
    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        db.execSQL("DROP TABLE IF EXISTS " + TABLE_NAME);
        onCreate(db);
    }

    // -------- CRUD OPERATIONS --------

    // INSERT
    public boolean insertStudent(String name, String course) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues cv = new ContentValues();
        cv.put(COL_NAME, name);
        cv.put(COL_COURSE, course);
        long result = db.insert(TABLE_NAME, null, cv);
        db.close();
        return result != -1;
    }

    // READ ALL → returns a Cursor for the caller to iterate.
    public Cursor getAllStudents() {
        SQLiteDatabase db = this.getReadableDatabase();
        return db.rawQuery("SELECT * FROM " + TABLE_NAME, null);
    }

    // UPDATE
    public boolean updateStudent(int id, String name, String course) {
        SQLiteDatabase db = this.getWritableDatabase();
        ContentValues cv = new ContentValues();
        cv.put(COL_NAME, name);
        cv.put(COL_COURSE, course);
        int rows = db.update(TABLE_NAME, cv, COL_ID + "=?",
                             new String[]{String.valueOf(id)});
        db.close();
        return rows > 0;
    }

    // DELETE
    public boolean deleteStudent(int id) {
        SQLiteDatabase db = this.getWritableDatabase();
        int rows = db.delete(TABLE_NAME, COL_ID + "=?",
                             new String[]{String.valueOf(id)});
        db.close();
        return rows > 0;
    }
}
```

### Step 2: Wire It Up in `MainActivity.java`

```java
// MainActivity.java
package com.example.ktusqlite;

import android.database.Cursor;
import android.os.Bundle;
import android.view.View;
import android.widget.*;
import androidx.appcompat.app.AppCompatActivity;

public class MainActivity extends AppCompatActivity {

    private DBHelper dbHelper;
    private EditText etName, etCourse;
    private TextView tvResult;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        dbHelper  = new DBHelper(this);
        etName    = findViewById(R.id.etName);
        etCourse  = findViewById(R.id.etCourse);
        tvResult  = findViewById(R.id.tvResult);
    }

    // Called when "Insert" button is tapped.
    public void onInsert(View v) {
        String name   = etName.getText().toString().trim();
        String course = etCourse.getText().toString().trim();
        if (dbHelper.insertStudent(name, course))
            Toast.makeText(this, "Inserted", Toast.LENGTH_SHORT).show();
        else
            Toast.makeText(this, "Failed", Toast.LENGTH_SHORT).show();
    }

    // Called when "View All" button is tapped.
    public void onView(View v) {
        Cursor c = dbHelper.getAllStudents();
        StringBuilder sb = new StringBuilder();
        if (c.getCount() == 0) {
            tvResult.setText("No records found.");
            return;
        }
        // Traverse row by row.
        while (c.moveToNext()) {
            sb.append("ID: ").append(c.getInt(0))
              .append(", Name: ").append(c.getString(1))
              .append(", Course: ").append(c.getString(2))
              .append("\n");
        }
        c.close();
        tvResult.setText(sb.toString());
    }
}
```

### Step 3: Lifecycle Note (Why `onDestroy` matters in SQLite)

> [!IMPORTANT]
> When you call `getWritableDatabase()` repeatedly in `Activity` callbacks, you may leave the DB open. In production code, override `onDestroy()` and call `dbHelper.close()` to release file handles.

